  ('aboriginal-6f0ba476-moex-00325', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '為避免破壞市場機能的正常運作，政府應對所有財貨課徵相同從價稅率之單一稅率，稱為：', '["租稅中立性原則", "受益原則", "量能課稅原則", "稅務簡化原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00326', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '課徵從量的特種銷售稅，在其他條件不變情況下，下列何種情況，其稅負完全由消費者負擔？', '["需求完全無價格彈性", "需求具完全價格彈性", "供給完全無價格彈性", "供給的價格彈性小於需求的價格彈性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00327', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '在獨占市場上，市場需求曲線為直線負斜率形狀，廠商的邊際成本為固定。政府對獨占廠商課徵 定額式（specific）商品稅，則消費者增加支付的價格為稅額的：', '["全部稅負", "四分之三", "二分之一", "四分之一"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00328', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '在完全競爭市場中課徵貨物稅，政府可採從價或從量方式課徵。假設其他條件不變且兩個課徵方 式可獲得相同稅收的情況下，從價與從量課徵方式對生產者的實際負擔何者較輕？', '["從價課徵", "從量課徵", "兩者相同", "無法比較"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00329', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-3e700a6a', 'sub-aboriginal-6f0ba476-07', NULL, 'single_choice', '假設商品X的邊際成本固定，受補償需求函數為Q=100－4P，其中Q及P分別為商品X的受補 償需求數量與價格。若課稅前的均衡數量為60，在其他條件不變下，現若政府對商品X課稅，使 商品X的稅後價格為15元，則此一課稅產生的超額負擔為多少元？', '["5元", "20元", "50元", "100元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "27a9a2d12389", "answer_pdf_sha1": "5efd0e81a826", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
